import { describe, it, expect } from 'vitest';
import { mockResponse } from './mock-response';

/* ===========================================================================
 * Characterization suite for the `mockResponse` test helper.
 *
 * `mockResponse` builds a minimal fetch `Response` stand-in consumed by every
 * ApiClient / app test. Its fallback behavior (how `ok`, `text()`, and `json()`
 * are derived) was previously described only in a doc comment — and that
 * comment referenced a characterization suite that no longer existed, leaving
 * the helper's observable behavior unverified. These tests pin the documented
 * contract directly so that a change to any fallback is caught here, regardless
 * of which higher-level test happens to exercise it.
 *
 * Implementation under test (for reference):
 *   const status = opts.status ?? 200;
 *   const ok     = opts.ok ?? (status >= 200 && status < 300);
 *   const text   = opts.text ?? JSON.stringify(opts.body ?? {});
 *   json: async () => opts.body ?? (opts.text ? JSON.parse(opts.text) : {}),
 * ========================================================================= */

describe('mockResponse — status', () => {
  it('defaults status to 200 when omitted', () => {
    expect(mockResponse({}).status).toBe(200);
  });

  it('honors an explicit status code', () => {
    expect(mockResponse({ status: 404 }).status).toBe(404);
    expect(mockResponse({ status: 503 }).status).toBe(503);
  });

  it('passes the status through verbatim (no coercion of the supplied value)', () => {
    expect(mockResponse({ status: 204 }).status).toBe(204);
  });
});

describe('mockResponse — ok is derived from status for 2xx ranges', () => {
  it('is true for the default 200', () => {
    expect(mockResponse({}).ok).toBe(true);
  });

  it('is true at the inclusive 2xx boundaries (200 and 299)', () => {
    expect(mockResponse({ status: 200 }).ok).toBe(true);
    expect(mockResponse({ status: 299 }).ok).toBe(true);
  });

  it('is false just below the 2xx range (199)', () => {
    expect(mockResponse({ status: 199 }).ok).toBe(false);
  });

  it('is false just above the 2xx range (300)', () => {
    expect(mockResponse({ status: 300 }).ok).toBe(false);
  });

  it('is false for common error statuses (404, 500, 503)', () => {
    expect(mockResponse({ status: 404 }).ok).toBe(false);
    expect(mockResponse({ status: 500 }).ok).toBe(false);
    expect(mockResponse({ status: 503 }).ok).toBe(false);
  });
});

describe('mockResponse — explicit ok overrides the status-derived value', () => {
  it('forces ok true even for a non-2xx status', () => {
    // `ok` is supplied, so it wins over the status range.
    expect(mockResponse({ ok: true, status: 500 }).ok).toBe(true);
  });

  it('forces ok false even for a 2xx status', () => {
    // Toolbar-handler tests rely on this: `mockResponse({ ok: false, status: 413 })`.
    expect(mockResponse({ ok: false, status: 200 }).ok).toBe(false);
    expect(mockResponse({ ok: false, status: 413 }).ok).toBe(false);
  });

  it('explicit ok:false beats status-derived true even when status is omitted', () => {
    // status defaults to 200 (would derive ok=true), but the explicit flag wins.
    expect(mockResponse({ ok: false }).ok).toBe(false);
  });
});

describe('mockResponse — text()', () => {
  it('returns the raw `text` option verbatim when supplied', async () => {
    const res = mockResponse({ text: 'Not Found' });
    expect(await res.text()).toBe('Not Found');
  });

  it('returns JSON-stringified `body` when `text` is omitted', async () => {
    const res = mockResponse({ body: { a: 1, b: [2, 3] } });
    expect(await res.text()).toBe(JSON.stringify({ a: 1, b: [2, 3] }));
  });

  it('defaults to "{}" when neither `text` nor `body` is supplied', async () => {
    // text = opts.text ?? JSON.stringify(opts.body ?? {})  =>  JSON.stringify({})  => '{}'
    expect(await mockResponse({}).text()).toBe('{}');
  });

  it('stringifies a falsy-but-defined body (e.g. 0, false, "") rather than "{}"', async () => {
    // `opts.body ?? {}` uses nullish-coalescing, so 0/false/'' survive.
    expect(await mockResponse({ body: 0 }).text()).toBe('0');
    expect(await mockResponse({ body: false }).text()).toBe('false');
    expect(await mockResponse({ body: '' }).text()).toBe('""');
  });

  it('is async (returns a Promise that resolves to a string)', async () => {
    const res = mockResponse({ text: 'hello' });
    expect(typeof res.text).toBe('function');
    const result = res.text();
    expect(result).toBeInstanceOf(Promise);
    expect(await result).toBe('hello');
  });

  it('returns the same text on repeated calls (no one-shot semantics)', async () => {
    const res = mockResponse({ body: { n: 1 } });
    expect(await res.text()).toBe('{"n":1}');
    expect(await res.text()).toBe('{"n":1}');
  });
});

describe('mockResponse — json() prefers an explicit body', () => {
  it('returns the body object as-is', async () => {
    const body = { path: '/x', entries: [] };
    expect(await mockResponse({ body }).json()).toEqual(body);
  });

  it('returns the body verbatim, not JSON.parse(JSON.stringify(body))', async () => {
    // Same reference identity must be preserved (no clone / re-parse round trip).
    const body = { a: 1, nested: { b: 2 } };
    expect(await mockResponse({ body }).json()).toBe(body);
  });

  it('returns arrays, numbers, and booleans unchanged', async () => {
    expect(await mockResponse({ body: [1, 2, 3] }).json()).toEqual([1, 2, 3]);
    expect(await mockResponse({ body: 42 }).json()).toBe(42);
    expect(await mockResponse({ body: true }).json()).toBe(true);
  });

  it('body wins over `text` when both are supplied', async () => {
    // json = opts.body ?? (...) — body short-circuits before `text` is parsed.
    const res = mockResponse({ body: { ok: true }, text: '{"ok":false}' });
    expect(await res.json()).toEqual({ ok: true });
    // `text()` still returns the raw text option untouched.
    expect(await res.text()).toBe('{"ok":false}');
  });
});

describe('mockResponse — json() nullish-body edge cases (?? semantics)', () => {
  it('treats an explicit null body as nullish and falls through to the text branch', async () => {
    // opts.body ?? (...) — `null` is nullish, so json() does NOT return null.
    // With no `text`, it falls all the way back to {}.
    expect(await mockResponse({ body: null }).json()).toEqual({});
  });

  it('parses `text` as JSON when body is null', async () => {
    expect(await mockResponse({ body: null, text: '{"x":42}' }).json()).toEqual({ x: 42 });
  });

  it('returns a falsy-but-defined body (0, false, "") unchanged', async () => {
    // Distinct from null/undefined: ?? only treats null/undefined as nullish.
    expect(await mockResponse({ body: 0 }).json()).toBe(0);
    expect(await mockResponse({ body: false }).json()).toBe(false);
    expect(await mockResponse({ body: '' }).json()).toBe('');
  });
});

describe('mockResponse — json() parses `text` when only text is given', () => {
  it('parses the raw text as JSON', async () => {
    const res = mockResponse({ text: '{"path":"/missing"}' });
    expect(await res.json()).toEqual({ path: '/missing' });
  });

  it('parses non-object JSON payloads (arrays, numbers)', async () => {
    expect(await mockResponse({ text: '[1,2,3]' }).json()).toEqual([1, 2, 3]);
    expect(await mockResponse({ text: '7' }).json()).toBe(7);
  });

  it('throws a SyntaxError when `text` is not valid JSON', async () => {
    // This is the error path ApiClient relies on: it reads .text(), never .json(),
    // on failures — but json() itself must surface invalid JSON rather than hide it.
    await expect(mockResponse({ text: 'Not Found' }).json()).rejects.toThrow(SyntaxError);
  });
});

describe('mockResponse — json() empty fallback', () => {
  it('returns {} when neither body nor text is supplied', async () => {
    // json = opts.body ?? (opts.text ? JSON.parse(opts.text) : {})  =>  {}
    expect(await mockResponse({}).json()).toEqual({});
  });

  it('returns {} when body and text are both explicitly undefined', async () => {
    expect(await mockResponse({ body: undefined, text: undefined }).json()).toEqual({});
  });

  it('is async (returns a Promise)', async () => {
    const res = mockResponse({});
    expect(typeof res.json).toBe('function');
    expect(res.json()).toBeInstanceOf(Promise);
  });
});

describe('mockResponse — returned object shape', () => {
  it('exposes ok, status, and async text()/json() methods', async () => {
    const res = mockResponse({ status: 200, body: { a: 1 } });
    expect(res).toHaveProperty('ok', true);
    expect(res).toHaveProperty('status', 200);
    expect(typeof res.text).toBe('function');
    expect(typeof res.json).toBe('function');
    expect(await res.json()).toEqual({ a: 1 });
  });

  it('reflects the same status on the returned object regardless of ok override', async () => {
    // `ok` and `status` are independent: overriding ok must not mutate status.
    const res = mockResponse({ ok: false, status: 413, text: 'too large' });
    expect(res.status).toBe(413);
    expect(res.ok).toBe(false);
    expect(await res.text()).toBe('too large');
  });
});

// @vitest-environment node
/**
 * Tests for `scripts/copy-assets.mjs` — the post-build asset-copy step invoked
 * by `npm run build` (`tsc && node scripts/copy-assets.mjs`).
 *
 * Pinned to the `node` environment (mirroring `src/app.css.test.ts` and
 * `src/readme.test.ts`): these tests spawn a child process and inspect files on
 * disk; they need no DOM and stay side-effect-light.
 *
 * Two concerns are covered:
 *
 *  1. CHARACTERIZATION (must keep holding): the script copies `src/app.css` to
 *     `wwwroot/dist/app.css` and vendors the bootstrap-icons CSS + fonts under
 *     `wwwroot/dist/icons/`. Asserted by RUNNING the real script as a child
 *     process and inspecting the produced files — so a refactor that breaks the
 *     copy is caught.
 *
 *  2. ERROR HANDLING: the `src/app.css` `copyFile` must catch only `ENOENT` and
 *     re-throw the rest (`EACCES`, `ENOSPC`, …). This is asserted both
 *     structurally (source has no bare swallowing catch and instead guards on
 *     `err.code !== 'ENOENT'`) AND behaviorally (forcing the copy to fail with
 *     `EACCES` must crash the script). The behavioral test is intentionally
 *     RACE-FREE: it makes the DESTINATION `wwwroot/dist/app.css` unreadable
 *     rather than the source `src/app.css`, which the parallel `app.css.test.ts`
 *     reads at load time.
 */
import { describe, it, expect } from 'vitest';
import { readFileSync, existsSync, chmodSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { spawnSync } from 'node:child_process';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, '..');
const SCRIPT_PATH = resolve(ROOT, 'scripts', 'copy-assets.mjs');
const SOURCE = readFileSync(SCRIPT_PATH, 'utf8');
const DIST = resolve(ROOT, 'wwwroot', 'dist');
const SRC_CSS = resolve(ROOT, 'src', 'app.css');
const DEST_CSS = resolve(DIST, 'app.css');
const BI_FONT_CSS = resolve(ROOT, 'node_modules', 'bootstrap-icons', 'font', 'bootstrap-icons.css');

/** True when the bootstrap-icons dependency (copied by the script) is installed. */
const HAS_BOOTSTRAP_ICONS = existsSync(BI_FONT_CSS);

/** Run the script synchronously via the current node binary. */
function runScript(): { status: number | null; stderr: string; stdout: string } {
  const r = spawnSync(process.execPath, [SCRIPT_PATH], { encoding: 'utf8' });
  return { status: r.status, stderr: r.stderr, stdout: r.stdout };
}

/* ===========================================================================
 * Characterization — the script copies the expected assets end-to-end.
 *
 * Skipped when bootstrap-icons is not installed (e.g. before `npm install`),
 * since the unguarded bootstrap-icons copy would then legitimately fail.
 * ========================================================================= */
describe.skipIf(!HAS_BOOTSTRAP_ICONS)(
  'scripts/copy-assets.mjs — end-to-end asset copy (characterization)',
  () => {
    it('exits 0 and copies src/app.css -> wwwroot/dist/app.css byte-for-byte', () => {
      const res = runScript();
      expect(res.status, `script stderr:\n${res.stderr}`).toBe(0);
      expect(existsSync(DEST_CSS), 'wwwroot/dist/app.css must exist').toBe(true);
      expect(readFileSync(DEST_CSS, 'utf8')).toBe(readFileSync(SRC_CSS, 'utf8'));
    });

    it('vendors bootstrap-icons CSS + fonts under wwwroot/dist/icons/', () => {
      expect(existsSync(resolve(DIST, 'icons', 'bootstrap-icons.css'))).toBe(true);
      expect(existsSync(resolve(DIST, 'icons', 'fonts', 'bootstrap-icons.woff2'))).toBe(true);
      expect(existsSync(resolve(DIST, 'icons', 'fonts', 'bootstrap-icons.woff'))).toBe(true);
    });
  },
);

/* ===========================================================================
 * Error-handling fix — the src/app.css copy must swallow ONLY ENOENT.
 *
 * These structural assertions fail against the current bare-`catch {}` source
 * and pass once the catch guards on `err.code !== 'ENOENT'` and re-throws.
 * ========================================================================= */
describe('scripts/copy-assets.mjs — src/app.css copy swallows only ENOENT', () => {
  it('wraps the src/app.css copyFile in a try/catch', () => {
    expect(SOURCE).toMatch(/try\s*\{[\s\S]*?copyFile\s*\(\s*srcPath/);
  });

  it('does NOT use a bare `catch {}` that swallows every error', () => {
    // `catch {` (no binding) silently eats all errors; `catch (err) {` does not.
    // This regex matches ONLY the bare form, never `catch (err) {`.
    expect(SOURCE).not.toMatch(/catch\s*\{/);
  });

  it('binds the caught error, guards on ENOENT, and re-throws the rest', () => {
    expect(SOURCE).toMatch(/catch\s*\(\s*\w+\s*\)/);
    expect(SOURCE).toMatch(/\.code\s*!==\s*['"]ENOENT['"]/);
    expect(SOURCE).toMatch(/throw\s+\w+/);
  });
});

/* ===========================================================================
 * Contrast — the bootstrap-icons copies must NOT swallow errors.
 *
 * Those copies are unguarded on purpose: a missing bootstrap-icons package must
 * fail the build loudly. Pinning this guards against accidentally wrapping them
 * in the same ENOENT-only catch.
 * ========================================================================= */
describe('scripts/copy-assets.mjs — bootstrap-icons copies propagate errors', () => {
  it('calls copyFile directly inside the asset loop (no try/catch around it)', () => {
    const loopMatch = SOURCE.match(
      /for\s*\(\s*const\s*\[\s*from\s*,\s*to\s*\]\s*of\s*biAssets\s*\)\s*\{([\s\S]*?)\}/,
    );
    expect(loopMatch, 'the `for (const [from, to] of biAssets)` loop must exist').not.toBeNull();
    expect(loopMatch![1]).toMatch(/await\s+copyFile/);
    expect(loopMatch![1]).not.toMatch(/\btry\s*\{/);
  });

  it('maps exactly the three expected bootstrap-icons assets', () => {
    expect(SOURCE).toMatch(/\[\s*'bootstrap-icons\.css'\s*,\s*'bootstrap-icons\.css'\s*\]/);
    expect(SOURCE).toMatch(
      /\[\s*'fonts\/bootstrap-icons\.woff2'\s*,\s*'fonts\/bootstrap-icons\.woff2'\s*\]/,
    );
    expect(SOURCE).toMatch(
      /\[\s*'fonts\/bootstrap-icons\.woff'\s*,\s*'fonts\/bootstrap-icons\.woff'\s*\]/,
    );
  });
});

/* ===========================================================================
 * Behavioral proof — a non-ENOENT error must actually crash the script.
 *
 * Race-free: it chmods the DESTINATION `wwwroot/dist/app.css` (unread by any
 * other test) to 000 so `copyFile` throws `EACCES` on overwrite. The script
 * must re-throw non-ENOENT errors and exit non-zero (it must not silently
 * swallow EACCES). Skipped on Windows where POSIX permission bits are not
 * honored.
 *
 * Permissions are always restored in `finally` so a failure cannot leave the
 * build output unreadable.
 * ========================================================================= */
describe.skipIf(!HAS_BOOTSTRAP_ICONS || process.platform === 'win32')(
  'scripts/copy-assets.mjs — surfaces non-ENOENT errors at runtime (behavioral)',
  () => {
    it('re-throws EACCES (read-only destination) instead of swallowing it', () => {
      // Baseline: the destination must exist so the copy hits an *overwrite*
      // EACCES (a create-in-readonly-dir EACCES would also trip the unguarded
      // bootstrap-icons mkdir and muddy the result).
      const baseline = runScript();
      expect(baseline.status, `baseline run failed:\n${baseline.stderr}`).toBe(0);
      expect(existsSync(DEST_CSS), 'dest must exist before making it read-only').toBe(true);

      chmodSync(DEST_CSS, 0o000);
      try {
        const res = runScript();
        expect(res.status, `script stderr:\n${res.stderr}`).not.toBe(0);
      } finally {
        chmodSync(DEST_CSS, 0o644);
      }
    });
  },
);

// @vitest-environment node
/**
 * Tests for the ignore patterns in `.prettierignore` and `.oxlintrc.json`.
 *
 * The build emits to `wwwroot/dist/` (see `tsconfig.json` `outDir` and
 * `scripts/copy-assets.mjs`). There is no root-level `dist/` directory and none
 * is ever created, so an ignore entry for bare `dist/` is DEAD — it ignores
 * nothing. Both files point at the real output, `wwwroot/dist/`.
 *
 * (`wwwroot/` is already ignored in both files, so `wwwroot/dist/` is already
 * transitively covered; the explicit `wwwroot/dist/` entry exists so removing
 * the dead `dist/` leaves no ambiguity about intent.)
 *
 * Pinned to the `node` environment: these read config files from disk and assert
 * on their contents (the same approach `src/app.css.test.ts` and
 * `src/readme.test.ts` use for static files).
 */
import { describe, it, expect } from 'vitest';
import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, '..');

const PRETTIERIGNORE = readFileSync(resolve(ROOT, '.prettierignore'), 'utf8');

interface OxlintConfig {
  $schema?: string;
  ignorePatterns: string[];
  categories?: Record<string, string>;
  rules?: Record<string, string>;
}
const OXLINTRC = JSON.parse(readFileSync(resolve(ROOT, '.oxlintrc.json'), 'utf8')) as OxlintConfig;

/** Escape a literal string for embedding in a RegExp. */
function escapeRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/** True when `text` contains a line whose entire content is exactly `line`. */
function hasLine(text: string, line: string): boolean {
  return new RegExp(`^${escapeRegex(line)}$`, 'm').test(text);
}

/* ===========================================================================
 * .prettierignore — target the real build output, drop the dead `dist/`.
 * ========================================================================= */
describe('.prettierignore — ignores the real build output wwwroot/dist/', () => {
  it('contains a `wwwroot/dist/` line', () => {
    expect(hasLine(PRETTIERIGNORE, 'wwwroot/dist/')).toBe(true);
  });

  it('does NOT contain the dead root-level `dist/` line', () => {
    // Anchored to a whole line: `^dist/$` matches a bare `dist/` line but NOT
    // `wwwroot/dist/`.
    expect(hasLine(PRETTIERIGNORE, 'dist/')).toBe(false);
  });
});

describe('.prettierignore — preserves every other ignore entry', () => {
  // Characterization: the `dist/` -> `wwwroot/dist/` change must not drop any
  // sibling entry.
  const kept = [
    'node_modules/',
    '.engin/',
    'wwwroot/',
    'bin/',
    'obj/',
    'coverage/',
    'SampleFiles/',
    'package-lock.json',
    '*.sln',
    '*.csproj',
    '*.cs',
  ];
  for (const pat of kept) {
    it(`still ignores ${pat}`, () => {
      expect(hasLine(PRETTIERIGNORE, pat), `.prettierignore must keep the ${pat} line`).toBe(true);
    });
  }
});

/* ===========================================================================
 * .oxlintrc.json — target the real build output, drop the dead `dist/`.
 * ========================================================================= */
describe('.oxlintrc.json — is valid JSON with an ignorePatterns array', () => {
  it('ignorePatterns is a non-empty array of strings', () => {
    expect(Array.isArray(OXLINTRC.ignorePatterns)).toBe(true);
    expect(OXLINTRC.ignorePatterns.length).toBeGreaterThan(0);
    expect(OXLINTRC.ignorePatterns.every((p) => typeof p === 'string')).toBe(true);
  });

  it('keeps the correctness category as error (config otherwise intact)', () => {
    expect(OXLINTRC.categories?.correctness).toBe('error');
  });
});

describe('.oxlintrc.json — ignorePatterns targets the real build output', () => {
  it('includes the "wwwroot/dist/" entry', () => {
    expect(OXLINTRC.ignorePatterns).toContain('wwwroot/dist/');
  });

  it('does NOT include the dead root-level "dist/" entry', () => {
    // Exact array-element check: 'wwwroot/dist/' is not equal to 'dist/'.
    expect(OXLINTRC.ignorePatterns).not.toContain('dist/');
  });
});

describe('.oxlintrc.json — preserves every other ignorePattern', () => {
  const kept = [
    'node_modules/',
    '.engin/',
    'wwwroot/',
    'bin/',
    'obj/',
    'SampleFiles/',
    'coverage/',
    'package-lock.json',
  ];
  for (const pat of kept) {
    it(`still ignores ${pat}`, () => {
      expect(
        OXLINTRC.ignorePatterns.includes(pat),
        `.oxlintrc.json must keep the "${pat}" ignorePattern`,
      ).toBe(true);
    });
  }
});

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ApiClient, type FileEntry, type BrowseResult, type SearchResult } from './api';
import { mockResponse } from './test-utils/mock-response';

describe('ApiClient', () => {
  let fetchMock: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    fetchMock = vi.fn();
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });

  describe('constructor', () => {
    it('defaults baseUrl to /api/files', () => {
      const client = new ApiClient();
      expect(client.downloadUrl('x')).toBe('/api/files/download?path=x');
    });

    it('honors a custom baseUrl', () => {
      const client = new ApiClient('/custom/api');
      expect(client.downloadUrl('x')).toBe('/custom/api/download?path=x');
    });
  });

  describe('browse', () => {
    it('GETs the browse endpoint with an encoded path and returns parsed JSON', async () => {
      const client = new ApiClient();
      const entries: FileEntry[] = [
        {
          name: 'a.txt',
          path: '/root/a.txt',
          isDirectory: false,
          size: 10,
          lastModified: '2024-01-01T00:00:00Z',
        },
      ];
      const result: BrowseResult = {
        path: '/root',
        parent: '/',
        entries,
        folderCount: 0,
        fileCount: 1,
        totalSize: 10,
      };
      fetchMock.mockResolvedValueOnce(mockResponse({ body: result }));

      const data = await client.browse('/root');

      expect(fetchMock).toHaveBeenCalledTimes(1);
      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/browse?path=' + encodeURIComponent('/root'));
      expect(init?.method).toBe('GET');
      expect(data).toEqual(result);
    });

    it('encodes special characters in the path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(
        mockResponse({
          body: { path: '', parent: null, entries: [], folderCount: 0, fileCount: 0, totalSize: 0 },
        }),
      );
      const tricky = '/foo bar/baz?x=1&y=2';
      await client.browse(tricky);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/browse?path=' + encodeURIComponent(tricky));
    });

    it('throws an Error containing status and response text on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 404, text: 'Not Found' }));

      await expect(client.browse('/missing')).rejects.toThrow('404: Not Found');
      await expect(client.browse('/missing')).rejects.toBeInstanceOf(Error);
    });

    it('throws a plain Error instance (not a string) on failure', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValue(mockResponse({ status: 500, text: 'boom' }));
      await expect(client.browse('/x')).rejects.toBeInstanceOf(Error);
    });
  });

  describe('search', () => {
    it('GETs the search endpoint with encoded query and path and returns parsed JSON', async () => {
      const client = new ApiClient();
      const results: FileEntry[] = [
        {
          name: 'match.txt',
          path: '/root/match.txt',
          isDirectory: false,
          size: 5,
          lastModified: '2024-02-02T00:00:00Z',
        },
      ];
      const out: SearchResult = { query: 'mat', path: '/root', results };
      fetchMock.mockResolvedValueOnce(mockResponse({ body: out }));

      const data = await client.search('mat', '/root');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe(
        '/api/files/search?query=' +
          encodeURIComponent('mat') +
          '&path=' +
          encodeURIComponent('/root'),
      );
      expect(init?.method).toBe('GET');
      expect(data).toEqual(out);
    });

    it('encodes special characters in both query and path', async () => {
      const client = new ApiClient();
